+        return std.mem.trimLeft(u8, str, " \t\n\r");
+    }
+
+    /// Strip whitespace from right
+    pub fn rstrip(self: PyValue) []const u8 {
+        const str = self.asString();
+        return std.mem.trimRight(u8, str, " \t\n\r");
